12	function assertKnownItemTypes(items: { type: string }[]): void {
13	  for (const item of items) {
14	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
15	      throw new Error(`Unknown item type: ${item.type}`);
16	    }
17	  }
18	}
