51	export function runScenario(scenario: any): { results: unknown[] } {
52	  const results: unknown[] = [];
53	  let quoteCount = 0;
54	  const remainingCaps = new Map<number, number>();
55	  for (const step of scenario.steps) {
56	    if (step.op === "quote") {
57	      assertKnownItemTypes(step.items);
58	      const premium = quote({
59	        customer: {
60	          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
61	          previousContracts: quoteCount,
62	        },
63	        items: step.items,
64	      });
65	      results.push({ premium });
66	      quoteCount++;
67	    } else if (step.op === "claim") {
68	      const policyStep = scenario.steps[step.policy];
69	      assertDamagesValid(policyStep.items, step.incident.damages);
70	      const { payout, remainingCap = 0 } = claim({
71	        items: policyStep.items,
72	        incident: step.incident,
73	        remainingCap: remainingCaps.get(step.policy),
74	      });
75	      remainingCaps.set(step.policy, remainingCap);
76	      results.push({ payout, remainingCap });
77	    }
78	  }
79	  return { results };
80	}
